import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const videoMarqueeItems = [
  { id: 1, src: "/assets/videos/cooking.mp4", alt: "Cooking", type: "video" },
  { id: 2, src: "/assets/videos/vid2.mp4", alt: "Vid 2", type: "video" },
  { id: 3, src: "/assets/videos/vid3.mp4", alt: "Vid 3", type: "video" },
  { id: 4, src: "/assets/videos/vid5.mp4", alt: "Vid 5", type: "video" },
  { id: 5, src: "/assets/videos/vid6.mp4", alt: "Vid 6", type: "video" },
];

const placeholderImages = [
  { id: 1, src: "/assets/amb.jpg", alt: "Ambience" },
  { id: 2, src: "/assets/apr.jpg", alt: "Aperitif" },
  { id: 3, src: "/assets/ballent.jpg", alt: "Ballentine" },
  { id: 4, src: "/assets/bl.jpg", alt: "Bar Lounge" },
  { id: 5, src: "/assets/bn.jpg", alt: "Bar Night" },
  { id: 6, src: "/assets/dj.jpg", alt: "DJ Night" },
  { id: 7, src: "/assets/dri.jpg", alt: "Drinks" },
  { id: 8, src: "/assets/f1.jpg", alt: "Food" },
  { id: 9, src: "/assets/grp.jpg", alt: "Group" },
  { id: 10, src: "/assets/nod.jpg", alt: "Night Out" },
  { id: 11, src: "/assets/pic.jpg", alt: "Vibes" },
  { id: 12, src: "/assets/piz.jpg", alt: "Pizza" },
];

const MovingGallery = () => {
  const renderItem = (item) => {
    if (item.type === 'video') {
      return (
        <video
          key={item.id}
          preload="metadata"
          src={item.src}
          className="w-[200px] h-[350px] md:w-[250px] md:h-[440px] object-cover rounded-2xl shadow-2xl bg-black mx-4 inline-block"
          muted
          autoPlay
          loop
          playsInline
        />
      );
    }
    return (
      <motion.img
        key={item.id}
        src={item.src}
        alt={item.alt}
        className="w-[280px] md:w-[360px] h-[180px] md:h-[240px] object-cover rounded-xl mx-4 inline-block grayscale hover:grayscale-0 hover:scale-105"
        initial={{ opacity: 0.8 }}
        whileHover={{ scale: 1.05, opacity: 1 }}
        transition={{ duration: 0.3 }}
        loading="lazy"
      />
    );
  };

  return (
    <section className="py-20 overflow-hidden bg-black">
      <div className="text-center mb-20">
        <span className="font-accent text-gold text-sm tracking-[0.3em] uppercase block mb-6">
          Experience The Vibe
        </span>
        <h2 className="font-heading text-5xl md:text-6xl text-white">
          Corridor in Motion
        </h2>
      </div>

      {/* Videos Portrait Marquee */}
      <Marquee speed={25} gradient={false} pauseOnHover className="mb-16">
        {videoMarqueeItems.map(renderItem)}
      </Marquee>

      {/* Images LTR */}
      <Marquee speed={50} gradient={false} pauseOnHover className="mb-16">
        {placeholderImages.slice(0, 10).map(renderItem)}
      </Marquee>

      {/* Images RTL */}
      <Marquee speed={50} direction="right" gradient={false} pauseOnHover>
        {placeholderImages.slice(0, 6).map((item, index) => renderItem({...item, id: `rtl-${index}`}))}
      </Marquee>
    </section>
  );
};

export default MovingGallery;
